    pLocal,
    bulbPower,
    bulbBailoutRadius,
    bulbTrigMode,
    bulbTrigTermX,
    bulbTrigTermY,
    bulbTrigTermZ,
    sceneIterations,
    useOrbitTraps,
    orbit,
    planeTrap,
    originTrap
