    mapSimple(pWorld + e.xyy) - mapSimple(pWorld - e.xyy),
    mapSimple(pWorld + e.yxy) - mapSimple(pWorld - e.yxy),
    mapSimple(pWorld + e.yyx) - mapSimple(pWorld - e.yyx)
